def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        modifier = 1.0
        for j in range(1, 15):
            if j % 3 == 0:
                modifier *= 0.85
            if ratio < (0.03 * j):
                increment = (j ** 2) * (1 - ratio)**3 * modifier
                if (cap + j) % 5 == 0:
                    increment += np.log1p(j * ratio + item)
                else:
                    increment -= np.sqrt(j) * np.sin(ratio * j)
                score += increment
            else:
                base_exp = j * np.exp(-ratio * (j**0.8)) * modifier / (j + 2)
                trig_term = np.cos(ratio * j) if ((cap * j) % 4 == 0) else np.sin(ratio * j)
                score += base_exp + trig_term / (j + 1)
            if j % 2 == 0:
                penalty += np.tanh(score / (j + 2))
            else:
                penalty -= np.arctan(score / (j + 1))
            if (j % 5 == 0) and (cap % (j + 3) == 0):
                score += np.log1p(j) * np.tanh(ratio * j)
            elif (j % 7 == 0):
                penalty -= np.sqrt(j) * np.exp(-ratio * j)
        for k in range(1, 8):
            residual = cap - item * k
            if residual > 0:
                if residual % (k+1) == 0:
                    score += np.log1p(residual + k) / (k + 1.2)
                else:
                    penalty -= (residual ** 0.3) / (k + 2.1)
                if k % 3 == 0 and residual % 2 == 1:
                    penalty += np.sin(residual / (k+0.5)) * np.cos(item / (k+1))
            else:
                penalty -= abs(residual) * 0.15 * k
                if k % 4 == 0:
                    penalty += np.tanh(abs(residual) / (k + 1))
        complexity = 0.0
        for m in range(1, 4):
            temp = (score * penalty) / (cap * (m + 2))
            if temp > 0:
                complexity += np.sqrt(temp) * np.exp(-item / (m + 1))
            else:
                complexity -= np.log1p(abs(temp)) * np.cos(ratio * m)
        final_value = (score + penalty + complexity) / (cap + 2)
        if final_value > 0:
            priorities[i] = -final_value * np.exp(-ratio/2) * np.tanh(item / (cap + 1))
        else:
            priorities[i] = -final_value * (np.log1p(cap + item) + np.sqrt(item + ratio))
    return priorities
